document.addEventListener("DOMContentLoaded",function(){const e=[{id:"ms-workflow",title:"MS Workflow"},{id:"moonshot-creatures",title:"Moonshot Creatures"},{id:"drogon",title:"Drogon"},{id:"hiddenstudio",title:"Alterego"},{id:"chaosmonger",title:"Italia 2162"},{id:"luminairi",title:"Outpost Alpha"},{id:"grim",title:"Grim.exe Rig"}],t=window.location.pathname,i=t.substring(t.lastIndexOf("/")+1).replace(".html",""),n=e.findIndex(e=>e.id===i);if(-1===n)return;const o=document.querySelector(".nav-left"),d=document.querySelector(".nav-right");if(n>0){const t=e[n-1],i=document.createElement("a");i.href=`${t.id}.html`,i.classList.add("nav-link"),i.innerHTML="← Previous",o.appendChild(i)}if(n<e.length-1){const t=e[n+1],i=document.createElement("a");i.href=`${t.id}.html`,i.classList.add("nav-link"),i.innerHTML="Next →",d.appendChild(i)}});